import React, { useState } from "react";
import "./IncomeDistribution.css";
import { useNavigate } from "react-router-dom";

interface CoOwner {
  id: number;
  name: string;
  share: string;
  photo: File | null;
}

export const IncomeDistribution: React.FC = () => {
  const navigate = useNavigate();
  const [type, setType] = useState<"company" | "project">("company");
  const [projectName, setProjectName] = useState("");
  const [coOwners, setCoOwners] = useState<CoOwner[]>([
    { id: 1, name: "", share: "", photo: null },
    { id: 2, name: "", share: "", photo: null },
  ]);

  const handleNameChange = (id: number, value: string) => {
    setCoOwners((prev) =>
      prev.map((o) => (o.id === id ? { ...o, name: value } : o))
    );
  };

  const handleShareChange = (id: number, value: string) => {
    setCoOwners((prev) =>
      prev.map((o) => (o.id === id ? { ...o, share: value } : o))
    );
  };

  const handlePhotoChange = (id: number, file: File | null) => {
    setCoOwners((prev) =>
      prev.map((o) => (o.id === id ? { ...o, photo: file } : o))
    );
  };

  const addCoOwner = () => {
    const newId = coOwners.length + 1;
    setCoOwners((prev) => [
      ...prev,
      { id: newId, name: "", share: "", photo: null },
    ]);
  };

  const ordinal = (n: number) => {
    const words = ["першого", "Другого", "Третього", "Четвертого", "П'ятого"];
    return words[n - 1] ?? `${n}-го`;
  };

  return (
    <div className="distribution-wrapper">
      {/* Radio: company or project */}
      <div className="distribution-card">
          <div className="radio-group">
            <label className="radio-label">
              <input
                type="radio"
                name="type"
                checked={type === "company"}
                onChange={() => setType("company")}
              />
              Назва компанії
            </label>
            <label className="radio-label">
              <input
                type="radio"
                name="type"
                checked={type === "project"}
                onChange={() => setType("project")}
              />
              Назва проєкту
            </label>
          </div>
          {/* Project/Company name */}
          <div className="field-group">
            <label className="field-label">Вкажіть назву</label>
            <input
              className="field-input"
              type="text"
              placeholder="ввести назву компанії || проєкту"
              value={projectName}
              onChange={(e) => setProjectName(e.target.value)}
            />
          </div>
          {/* Co-owners */}
          {coOwners.map((owner, index) => (
            <div className="coowner-block" key={owner.id}>
              <div className="field-group">
                <label className="field-label">
                  ПІП {ordinal(index + 1)} співвласника
                </label>
                <input
                  className="field-input"
                  type="text"
                  placeholder="піп співвласника"
                  value={owner.name}
                  onChange={(e) => handleNameChange(owner.id, e.target.value)}
                />
              </div>
              <div className="field-group">
                <label className="field-label">
                  Частка компанії {ordinal(index + 1)} співвласника (1% - 99%)
                </label>
                <input
                  className="field-input"
                  type="number"
                  min={1}
                  max={99}
                  placeholder="введіть __%"
                  value={owner.share}
                  onChange={(e) => handleShareChange(owner.id, e.target.value)}
                />
              </div>
              <input
                type="file"
                accept="image/*"
                id={`photo-${owner.id}`}
                style={{ display: "none" }}
                onChange={(e) =>
                  handlePhotoChange(owner.id, e.target.files?.[0] ?? null)
                }
              />
              <button
                className="photo-btn"
                onClick={() =>
                  document.getElementById(`photo-${owner.id}`)?.click()
                }
              >
                {owner.photo ? "Фото додано ✓" : "Додати фото"}
              </button>
            </div>
          ))}
          {/* Add co-owner */}
          <button className="add-coowner-btn" onClick={addCoOwner}>
            Додати нового співвласника
          </button>
          {/* Continue */}
          <button className="continue-btn" onClick={() => navigate("/dashboard")}>
            Продовжити
          </button>
        </div>
      </div>
  );
};
